using System.ComponentModel.DataAnnotations;

namespace sv_32b917fc1a9a4d0490f33897940089b5.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models

public class PersonalInfoModel
{
    [Required(ErrorMessage = "Full name is required.")]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone number is required.")]
    [Phone(ErrorMessage = "Invalid phone format.")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Address is required.")]
    public string Address { get; set; } = "";
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

@using sv_32b917fc1a9a4d0490f33897940089b5.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>
        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name</label>
                <input class="form-control @FieldClass("Company")" @bind="Entry.Company" />
                @if (Errors.TryGetValue($"{Index}.Company", out var companyErr))
                {
                    <div class="invalid-feedback d-block">@companyErr</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input class="form-control @FieldClass("Title")" @bind="Entry.Title" />
                @if (Errors.TryGetValue($"{Index}.Title", out var titleErr))
                {
                    <div class="invalid-feedback d-block">@titleErr</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control @FieldClass("StartDate")" @bind="Entry.StartDate" />
                @if (Errors.TryGetValue($"{Index}.StartDate", out var startErr))
                {
                    <div class="invalid-feedback d-block">@startErr</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" @bind="Entry.IsCurrent"
                           @onclick="HandleCurrentToggle" id="current-@Index" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" @bind="Entry.Description" rows="3"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();

    private string FieldClass(string field) =>
        Errors.ContainsKey($"{Index}.{field}") ? "is-invalid" : "";

    private void HandleCurrentToggle()
    {
        if (!Entry.IsCurrent)
            Entry.EndDate = null;
    }
}

