.step-indicator {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0 0 1.5rem;
    counter-reset: step;
}

.step-item {
    flex: 1;
    text-align: center;
    position: relative;
}

/* Connector line between steps */
.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background-color: #e9ecef;
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.active + .step-item::before,
.step-item.completed + .step-item.completed::before {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 0.4rem;
    background-color: #e9ecef;
    color: #6c757d;
    position: relative;
    z-index: 1;
    transition: background-color 0.2s, color 0.2s;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
    cursor: pointer;
}

.step-item.future .step-circle {
    opacity: 0.5;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
    line-height: 1.2;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

