+<h4 class="mb-3">Cover Letter</h4>
+
+<div class="mb-3">
+    <textarea class="form-control @(hasError ? "is-invalid" : "")"
+              value="@CoverLetter"
+              @oninput="HandleInput"
+              rows="12"
+              maxlength="@MaxLength"
+              placeholder="Write your cover letter here..."></textarea>
+    <div class="d-flex justify-content-between mt-1">
+        @if (hasError)
+        {
+            <div class="text-danger small">Cover letter is required.</div>
+        }
+        else
+        {
+            <div></div>
+        }
+        <div class="text-muted small">@(CoverLetter?.Length ?? 0) / @MaxLength characters</div>
+    </div>
+</div>
+
+<div class="d-flex justify-content-between mt-4">
+    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
+    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
+</div>
+
+@code {
+    [Parameter] public string CoverLetter { get; set; } = "";
+    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
+    [Parameter] public EventCallback OnNext { get; set; }
+    [Parameter] public EventCallback OnBack { get; set; }
+
+    private const int MaxLength = 2000;
+    private bool hasError;
+
+    private async Task HandleInput(ChangeEventArgs e)
+    {
+        var value = e.Value?.ToString() ?? "";
+        await CoverLetterChanged.InvokeAsync(value);
+    }
+
+    private async Task HandleNext()
+    {
+        hasError = string.IsNullOrWhiteSpace(CoverLetter);
+        if (!hasError)
+            await OnNext.InvokeAsync();
+    }
