@using sv_32b917fc1a9a4d0490f33897940089b5.Models

<h4 class="mb-4">Review &amp; Submit</h4>

@if (SubmittedId is not null)
{
    <div class="alert alert-success text-center py-4">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p class="mb-0">Your application has been submitted successfully.</p>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>.</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Personal Information</h5>
            <a href="" @onclick="() => OnEditStep.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Work History</h5>
            <a href="" @onclick="() => OnEditStep.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong>
                    <br />
                    <span class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">References</h5>
            <a href="" @onclick="() => OnEditStep.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br />
                    <span class="text-muted">@r.Email &middot; @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Cover Letter</h5>
            <a href="" @onclick="() => OnEditStep.InvokeAsync(4)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(submitError))
    {
        <div class="alert alert-danger">@submitError</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public int? SubmittedId { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool isSubmitting;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

@page "/apply"
@rendermode InteractiveServer

@using sv_32b917fc1a9a4d0490f33897940089b5.Components.JobApplication
@using sv_32b917fc1a9a4d0490f33897940089b5.Models

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo" OnNext="HandleNext" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries" OnNext="HandleNext" OnBack="PreviousStep" />
            break;
        case 3:
            <ReferencesStep References="references" OnNext="HandleNext" OnBack="PreviousStep" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="HandleNext" OnBack="PreviousStep" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        SubmittedId="submittedId"
                        OnEditStep="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";
    private int? submittedId;

    private void HandleNext()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 1)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate!.Value, e.IsCurrent ? null : e.EndDate, e.Description
            )).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        submittedId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

